protected virtual void TcpClient.Dispose(bool disposing)
{
    if (Logging.On)
    {
        Logging.Enter(Logging.Sockets, this, "Dispose", "");
    }
    if (this.m_CleanedUp)
    {
        if (Logging.On)
        {
